const decodoOut = $input.first().json;
const rawContent = decodoOut.markdown || decodoOut.content || decodoOut.body || decodoOut.data || JSON.stringify(decodoOut);
const config = $('Search Config').first().json;
const niche = config.niche;
const city = config.city;
const MAX = config.maxLeads || 15;
const phoneRx = /\(?\d{3}\)?[\s.\-]?\d{3}[\s.\-]?\d{4}/;
const urlRx = /https?:\/\/[^\s)>"',]+/;
const ratingRx = /([0-9]\.[0-9])\s*(?:stars?|out of|\(|·|rating)/i;
const addrWords = ['Ave','Avenue','St','Street','Blvd','Boulevard','Rd','Road','Dr','Drive','Lane','Ln','Way','Court','Ct','Plaza','Pl','Suite','Ste'];
const lines = rawContent.split('\n').map(l => l.replace(/[*#`|]/g,'').trim()).filter(l => l.length > 3);
const leads = [];
let current = {};
let leadCount = 0;
const isAddress = (line) => addrWords.some(kw => line.includes(kw)) && /\d/.test(line);
const flush = () => {
  if (current.businessName && (current.phone || current.website || current.address)) {
    leads.push({ json: { id: `lead_${Date.now()}_${leadCount}`, businessName: current.businessName || '', address: current.address || '', phone: current.phone || '', website: current.website || '', rating: current.rating || '', niche, city, status: 'New', aiScore: '', aiSummary: '', email: '', emailSent: 'No', scrapedAt: new Date().toISOString() } });
    leadCount++;
  }
};
for (let i = 0; i < lines.length && leadCount < MAX; i++) {
  const line = lines[i];
  const pm = line.match(phoneRx);
  if (pm && current.businessName && !current.phone) { current.phone = pm[0]; continue; }
  const um = line.match(urlRx);
  if (um && current.businessName) { const u = um[0].replace(/[,.)]+$/,''); if (!u.includes('google') && !u.includes('goo.gl') && !u.includes('maps')) { current.website = u; continue; } }
  const rm = line.match(ratingRx);
  if (rm && current.businessName && !current.rating) { current.rating = parseFloat(rm[1]); continue; }
  if (isAddress(line) && current.businessName && !current.address) { current.address = line; continue; }
  if (/^[A-Z]/.test(line) && line.length >= 5 && line.length <= 75 && !line.includes('http') && !pm) { flush(); current = { businessName: line }; }
}
flush();
if (leads.length === 0) { return [{ json: { error: 'No leads parsed', rawSample: rawContent.substring(0,800), niche, city } }]; }
return leads;

const leadData = $('Split In Batches').item.json;
const aiRaw = $json.message?.content || $json.choices?.[0]?.message?.content || $json.content || '';
let aiResult = {};
try {
  const cleaned = aiRaw.replace(/```json?/gi,'').replace(/```/g,'').trim();
  aiResult = JSON.parse(cleaned);
} catch(e) {
  aiResult = { aiScore: 5, aiSummary: 'AI parse failed: ' + aiRaw.substring(0,100), employeeCount: 'Unknown', businessType: 'Unknown', techSavviness: 'Unknown', painPoints: '', email: '' };
}
return { json: { id: leadData.id, businessName: leadData.businessName, address: leadData.address||'', phone: leadData.phone||'', website: leadData.website||'', rating: leadData.rating||'', niche: leadData.niche||'', city: leadData.city||'', status: 'Enriched', aiScore: aiResult.aiScore||'', aiSummary: aiResult.aiSummary||'', employeeCount: aiResult.employeeCount||'', businessType: aiResult.businessType||'', techSavviness: aiResult.techSavviness||'', painPoints: aiResult.painPoints||'', email: aiResult.email||leadData.email||'', emailSent: leadData.emailSent||'No', scrapedAt: leadData.scrapedAt||'' } };

const config = $('Search Config').first().json;
const threshold = Number(config.scoreThreshold) || 6;
const qualifiedLeads = $input.all().filter(item => {
  const score = Number(item.json.aiScore) || 0;
  const hasEmail = item.json.email && item.json.email.trim().length > 3;
  const hasWebsite = item.json.website && item.json.website.trim().length > 5;
  const notContacted = item.json.emailSent !== 'Yes';
  return score >= threshold && hasEmail && hasWebsite && notContacted;
});
if (qualifiedLeads.length === 0) {
  return [{ json: { __noLeads: true, message: `No leads meet threshold: score >= ${threshold} with email` } }];
}
return qualifiedLeads;

const lead = $('Merge Lead + Content').item.json;
const aiRaw = $json.message?.content || $json.choices?.[0]?.message?.content || $json.content || '';
let emailData = {};
try {
  const cleaned = aiRaw.replace(/```json?/gi,'').replace(/```/g,'').trim();
  emailData = JSON.parse(cleaned);
} catch(e) {
  emailData = {
    emailSubject: `Quick question about ${lead.businessName}`,
    emailBodyHtml: `<p>Hi there,</p><p>I came across ${lead.businessName} and was impressed by what you've built. I specialize in ${lead.senderOffer} and thought there might be a fit.</p><p>Open to a quick 15-minute call?</p><p>Best,<br>${lead.senderName}<br>${lead.senderCompany}</p>`
  };
}
if (!emailData.emailSubject || emailData.emailSubject.length < 5) emailData.emailSubject = `Quick question, ${lead.businessName}`;
if (!emailData.emailBodyHtml || emailData.emailBodyHtml.length < 20) emailData.emailBodyHtml = `<p>Hi there,</p><p>Loved your work at ${lead.businessName}. Would love to connect about ${lead.senderOffer}.</p><p>Worth a quick chat?</p><p>${lead.senderName}</p>`;
return { json: { id: lead.id, businessName: lead.businessName, recipientEmail: lead.recipientEmail, website: lead.website, emailSubject: emailData.emailSubject, emailBodyHtml: emailData.emailBodyHtml, senderName: lead.senderName, senderCompany: lead.senderCompany } };
